// ===================================================
// WF-05 5a-1: last_poll_time 파싱 + 메이크샵 주문 조회 URL 구성
// ===================================================

const response = $input.first().json;
const list = response.list || [];

let lastPollTime;
if (list.length > 0 && list[0].setting_value) {
  lastPollTime = list[0].setting_value;
} else {
  // 최초 실행: 1시간 전부터 검색
  const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000);
  lastPollTime = oneHourAgo.toISOString().split('T')[0];
}

// 날짜만 추출 (YYYY-MM-DD)
const sdate = lastPollTime.split(' ')[0].split('T')[0];
const now = new Date();
const pad = (n) => String(n).padStart(2, '0');
// KST 보정 (+9시간)
const kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);
const edate = kst.getFullYear() + '-' + pad(kst.getMonth() + 1) + '-' + pad(kst.getDate());

// NocoDB에 last_poll_time 레코드가 있는지 여부 (업데이트 vs 생성 구분용)
const hasRecord = list.length > 0;
const recordId = hasRecord ? (list[0].Id || list[0].id || '') : '';

return [{
  json: {
    sdate,
    edate,
    lastPollTime,
    hasRecord,
    recordId,
    pollStartTime: now.toISOString()
  }
}];

// ===================================================
// WF-05 5a-2: 주문 목록 + 클래스맵 결합, 클래스 상품만 필터링
// 같은 order_id 안에 묶음 키트 상품이 함께 담겼는지 감지
// ===================================================

const ordersResponse = $('Makeshop Search Orders').first().json;
const classesResponse = $('NocoDB Get Classes Map').first().json;
const pollMeta = $('Parse Poll Time').first().json;

const orders = ordersResponse.list || ordersResponse.datas || [];
const classesList = classesResponse.list || [];

function extractBrandUid(raw) {
  const text = String(raw || '').replace(/\s+/g, '').trim();
  const match = text.match(/[?&]branduid=([^&#]+)/i);
  if (match && match[1]) return decodeURIComponent(match[1]);
  if (/^[A-Za-z0-9_-]{4,64}$/.test(text)) return text;
  return '';
}

const classMap = {};
for (const c of classesList) {
  const pid = String(c.makeshop_product_id || '').trim();
  if (!pid) continue;
  let partnerCode = '';
  if (Array.isArray(c.partner_code) && c.partner_code.length > 0) {
    partnerCode = c.partner_code[0].partner_code || c.partner_code[0].Title || '';
  } else if (typeof c.partner_code === 'string') {
    partnerCode = c.partner_code;
  }
  classMap[pid] = {
    class_id: c.class_id || '',
    class_name: c.class_name || '',
    partner_code: partnerCode,
    location: c.location || '',
    price: Number(c.price) || 0,
    kit_enabled: Number(c.kit_enabled) || 0,
    kit_items: c.kit_items || '',
    kit_bundle_branduid: extractBrandUid(c.kit_bundle_branduid || '')
  };
}

const orderGroups = {};
for (const order of orders) {
  const orderId = String(order.order_id || order.orderno || '').trim();
  const branduid = String(order.branduid || '').trim();
  if (!orderId) continue;
  if (!orderGroups[orderId]) {
    orderGroups[orderId] = {
      order_id: orderId,
      member_id: String(order.member_id || order.userid || '').trim(),
      buyer_name: String(order.buyer_name || order.name || '').trim(),
      buyer_email: String(order.buyer_email || order.email || '').trim(),
      buyer_phone: String(order.buyer_phone || order.phone || '').trim(),
      lines: [],
      branduids: []
    };
  }
  orderGroups[orderId].lines.push({
    order_id: orderId,
    branduid: branduid,
    option_value: String(order.option_value || order.option || '').trim(),
    quantity: Number(order.quantity || order.ea || 1),
    settle_price: Number(order.settle_price || order.price || 0),
    product_name: String(order.product_name || order.goods_name || '').trim()
  });
  if (branduid && orderGroups[orderId].branduids.indexOf(branduid) === -1) {
    orderGroups[orderId].branduids.push(branduid);
  }
}

const classOrders = [];
for (const orderId of Object.keys(orderGroups)) {
  const group = orderGroups[orderId];
  let classLine = null;
  let classData = null;
  for (const line of group.lines) {
    if (line.branduid && classMap[line.branduid]) {
      classLine = line;
      classData = classMap[line.branduid];
      break;
    }
  }
  if (!classLine || !classData) continue;

  const bundleBrandUid = String(classData.kit_bundle_branduid || '').trim();
  let bundleLine = null;
  if (bundleBrandUid) {
    bundleLine = group.lines.find((line) => line.branduid === bundleBrandUid) || null;
  }

  classOrders.push({
    order_id: group.order_id,
    branduid: classLine.branduid,
    member_id: group.member_id,
    buyer_name: group.buyer_name,
    buyer_email: group.buyer_email,
    buyer_phone: group.buyer_phone,
    option_value: classLine.option_value,
    quantity: classLine.quantity,
    settle_price: classLine.settle_price,
    classData: classData,
    all_branduids: group.branduids,
    order_lines: group.lines,
    bundle_branduid: bundleBrandUid,
    bundle_line: bundleLine,
    kitBundleSelected: !!bundleLine
  });
}

return [{
  json: {
    totalOrders: orders.length,
    classOrders,
    classOrderCount: classOrders.length,
    pollMeta
  }
}];

// ===================================================
// WF-05 5a-3: 주문 0건 -> 폴링 로그만 기록하고 종료
// ===================================================

const data = $('Filter Class Orders').first().json;
const pollMeta = data.pollMeta;

return [{
  json: {
    _logData: {
      poll_time: pollMeta.pollStartTime,
      orders_found: data.totalOrders,
      class_orders: 0,
      settlements_created: 0,
      errors: 0,
      note: '클래스 주문 없음'
    },
    _updatePollTime: true,
    _pollMeta: pollMeta
  }
}];

// ===================================================
// WF-05 5a-4: 주문 배열을 개별 아이템으로 분할 (Loop 준비)
// 각 주문을 별도 아이템으로 출력
// ===================================================

const data = $input.first().json;
const orders = data.classOrders || [];
const pollMeta = data.pollMeta;

const items = orders.map(order => ({
  json: {
    ...order,
    _pollMeta: pollMeta
  }
}));

return items;

// ===================================================
// WF-05 5a-5: 중복 체크 결과 판정 + 정산 레코드 데이터 구성
// 이미 처리된 주문이면 스킵, 신규면 정산 레코드 생성 준비
// ===================================================

const dupResponse = $input.first().json;
const dupList = dupResponse.list || [];
const order = $('Split Orders').item.json;

if (dupList.length > 0) {
  // 이미 처리된 주문
  return [{
    json: {
      _skip: true,
      _reason: 'duplicate',
      order_id: order.order_id
    }
  }];
}

// 수수료 계산을 위해 파트너 조회 필요
return [{
  json: {
    _skip: false,
    order_id: order.order_id,
    branduid: order.branduid,
    member_id: order.member_id,
    buyer_name: order.buyer_name,
    buyer_email: order.buyer_email,
    buyer_phone: order.buyer_phone,
    option_value: order.option_value,
    quantity: order.quantity,
    settle_price: order.settle_price,
    classData: order.classData,
    _pollMeta: order._pollMeta
  }
}];

// ===================================================
// WF-05 5a-6: 수수료 계산 + settlement 레코드 구성
// WF-04 Calculate Commission 로직 재사용
// D+3 정산: PENDING_SETTLEMENT 상태로 기록
// ===================================================

const partnerResponse = $input.first().json;
const partnerList = partnerResponse.list || [];
const order = $('Check Dup Result').item.json;

// 파트너 정보 없으면 에러 처리
if (partnerList.length === 0) {
  return [{
    json: {
      _error: true,
      _errorMsg: '파트너 정보 없음: ' + order.classData.partner_code,
      order_id: order.order_id
    }
  }];
}

const partner = partnerList[0];

// 자기 결제 방지
const isSelfPurchase = (order.member_id === partner.member_id);

// 수수료 계산 (개선안 B 적용)
const COMMISSION_RATES = {
  BLOOM:      { commissionRate: 0.25, reserveRate: 0.80 },
  GARDEN:     { commissionRate: 0.20, reserveRate: 0.80 },
  ATELIER:    { commissionRate: 0.15, reserveRate: 0.80 },
  AMBASSADOR: { commissionRate: 0.10, reserveRate: 0.80 },
  SILVER:     { commissionRate: 0.25, reserveRate: 0.80 },
  GOLD:       { commissionRate: 0.20, reserveRate: 0.80 },
  PLATINUM:   { commissionRate: 0.15, reserveRate: 0.80 }
};

const grade = (partner.grade || 'BLOOM').toUpperCase();
const config = COMMISSION_RATES[grade] || COMMISSION_RATES.BLOOM;
const orderAmount = order.settle_price;
const commissionAmount = Math.round(orderAmount * config.commissionRate);
const reserveAmount = Math.round(commissionAmount * config.reserveRate);

// settlement_id 생성
const now = new Date();
const pad = (n) => String(n).padStart(2, '0');
const dateStr = String(now.getFullYear()) + pad(now.getMonth() + 1) + pad(now.getDate());
const randomSuffix = String(Math.floor(100000 + Math.random() * 900000));
const settlementId = 'STL_' + dateStr + '_' + randomSuffix;

// D+3 정산일: 수업일(option_value) 또는 주문일 기준
let classDateStr = order.option_value || '';
// YYYY-MM-DD 형식이 아니면 오늘 날짜 사용
if (!/^\d{4}-\d{2}-\d{2}/.test(classDateStr)) {
  classDateStr = now.toISOString().split('T')[0];
}
classDateStr = classDateStr.substring(0, 10);
const classDate = new Date(classDateStr + 'T00:00:00+09:00');
const dueDate = new Date(classDate.getTime() + 3 * 24 * 60 * 60 * 1000);
const dueDateStr = dueDate.getFullYear() + '-' + pad(dueDate.getMonth() + 1) + '-' + pad(dueDate.getDate());

// 개인정보 마스킹
function maskPhone(phone) {
  if (!phone || phone.length < 7) return '***';
  return phone.substring(0, 3) + '-****-' + phone.substring(phone.length - 4);
}
function maskName(name) {
  if (!name || name.length < 2) return '*';
  return name.charAt(0) + '*'.repeat(name.length - 1);
}

const status = isSelfPurchase ? 'SELF_PURCHASE' : 'PENDING_SETTLEMENT';

return [{
  json: {
    _error: false,
    _isSelfPurchase: isSelfPurchase,
    settlement: {
      settlement_id: settlementId,
      order_id: order.order_id,
      class_id: order.classData.class_id,
      partner_code: order.classData.partner_code,
      member_id: order.member_id,
      order_amount: orderAmount,
      commission_rate: config.commissionRate,
      commission_amount: commissionAmount,
      reserve_rate: config.reserveRate,
      reserve_amount: reserveAmount,
      class_date: classDateStr,
      settlement_due_date: dueDateStr,
      student_count: order.quantity,
      status: status,
      student_name: order.buyer_name,
      student_email: order.buyer_email,
      student_phone: maskPhone(order.buyer_phone),
      created_date: now.toISOString(),
      retry_count: 0
    },
    display: {
      className: order.classData.class_name,
      partnerName: partner.partner_name || '',
      maskedName: maskName(order.buyer_name),
      grade,
      amount: orderAmount.toLocaleString('ko-KR') + '원',
      commission: commissionAmount.toLocaleString('ko-KR') + '원',
      reserve: reserveAmount.toLocaleString('ko-KR') + '원',
      dueDate: dueDateStr
    }
  }
}];

// ===================================================
// WF-05 5a-6b: tbl_Schedules booked_count 증가
// Create Settlement 성공 후 해당 스케줄의 booked_count 업데이트
// ===================================================

const https = require('https');
const settlement = $('Calc Commission').first().json.settlement;
const createResult = $input.first().json;

// 정산 레코드 생성 실패 시 스킵
if (!createResult.Id && !createResult.id) {
  return [$input.first()];
}

const classId = settlement.class_id;
const classDate = settlement.class_date;
const studentCount = settlement.student_count || 1;

function nocoRequest(method, path, body) {
  return new Promise((resolve, reject) => {
    const options = {
      hostname: 'nocodb.pressco21.com',
      path: '/api/v1/db/data/noco/' + $env.NOCODB_PROJECT_ID + path,
      method: method,
      headers: {
        'xc-token': $env.NOCODB_API_TOKEN,
        'Content-Type': 'application/json'
      }
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => {
        try { resolve(JSON.parse(data)); } catch(e) { resolve(data); }
      });
    });
    req.on('error', reject);
    if (body) req.write(JSON.stringify(body));
    req.end();
  });
}

try {
  // tbl_Schedules에서 class_id + schedule_date 매칭 스케줄 조회
  const schedResult = await nocoRequest('GET',
    '/mschd3d81ad88fb?where=(class_id,eq,' + encodeURIComponent(classId) + ')~and(schedule_date,eq,' + encodeURIComponent(classDate) + ')~and(status,eq,active)&limit=1'
  );
  const schedList = schedResult.list || [];

  if (schedList.length > 0) {
    const sched = schedList[0];
    const newBookedCount = (Number(sched.booked_count) || 0) + Number(studentCount);
    // PATCH로 booked_count 업데이트
    await nocoRequest('PATCH',
      '/mschd3d81ad88fb/' + sched.Id,
      { booked_count: newBookedCount }
    );
  }
} catch(e) {
  // booked_count 업데이트 실패해도 정산은 이미 생성됨 - 로그만 남김
}

return [$input.first()];

// ===================================================
// WF-05 5a-6c: 재료키트 자동 배송 처리
// 묶음 키트 상품이 실제로 함께 결제된 주문만 키트 발송 처리
// ===================================================

const https = require('https');
const settlement = $('Calc Commission').item.json.settlement;
const createResult = $('Create Settlement').first().json;
const orderContext = $('Check Dup Result').item.json;

if ((!createResult.Id && !createResult.id) || !orderContext || !orderContext.kitBundleSelected) {
  return [$input.first()];
}

const classId = settlement.class_id;

function nocoRequest(method, path, body) {
  return new Promise((resolve, reject) => {
    const options = {
      hostname: 'nocodb.pressco21.com',
      path: '/api/v1/db/data/noco/' + $env.NOCODB_PROJECT_ID + path,
      method: method,
      headers: {
        'xc-token': $env.NOCODB_API_TOKEN,
        'Content-Type': 'application/json'
      }
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try { resolve(JSON.parse(data)); } catch (e) { resolve(data); }
      });
    });
    req.on('error', reject);
    if (body) req.write(JSON.stringify(body));
    req.end();
  });
}

function sendTelegram(message) {
  return new Promise((resolve, reject) => {
    const chatId = $env.TELEGRAM_CHAT_ID || '7713811206';
    const postData = JSON.stringify({ chat_id: chatId, text: message, parse_mode: 'HTML' });
    const options = {
      hostname: 'api.telegram.org',
      path: '/bot' + $env.TELEGRAM_BOT_TOKEN + '/sendMessage',
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(postData) }
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => resolve(data));
    });
    req.on('error', reject);
    req.write(postData);
    req.end();
  });
}

function extractBrandUid(raw) {
  const text = String(raw || '').replace(/\s+/g, '').trim();
  const match = text.match(/[?&]branduid=([^&#]+)/i);
  if (match && match[1]) return decodeURIComponent(match[1]);
  if (/^[A-Za-z0-9_-]{4,64}$/.test(text)) return text;
  return '';
}

function normalizeKitProductUrl(raw) {
  const text = String(raw || '').trim();
  if (!text) return '';
  const brandUid = extractBrandUid(text);
  if (brandUid) {
    return '/shop/shopdetail.html?branduid=' + encodeURIComponent(brandUid);
  }
  if (/^https?:\/\//i.test(text) || text.indexOf('/shop/') === 0) {
    return text;
  }
  return '';
}

try {
  const classResult = await nocoRequest('GET', '/mpvsno4or6asbxk?where=(class_id,eq,' + encodeURIComponent(classId) + ')&fields=class_id,class_name,kit_enabled,kit_items,kit_bundle_branduid&limit=1');
  const classList = classResult.list || [];
  if (classList.length === 0) return [$input.first()];

  const cls = classList[0];
  const kitEnabled = Number(cls.kit_enabled) || 0;
  const expectedBundleBrandUid = extractBrandUid(cls.kit_bundle_branduid || orderContext.bundle_branduid || '');
  const actualBundleBrandUid = extractBrandUid(orderContext.bundle_line && orderContext.bundle_line.branduid || '');
  if (kitEnabled !== 1 || !expectedBundleBrandUid || expectedBundleBrandUid !== actualBundleBrandUid) {
    return [$input.first()];
  }

  let kitItems = [];
  try { kitItems = cls.kit_items ? JSON.parse(cls.kit_items) : []; } catch (e) {}
  if (!Array.isArray(kitItems) || kitItems.length === 0) return [$input.first()];

  let itemsList = '';
  for (const item of kitItems) {
    const qty = (item.quantity || 1) * (settlement.student_count || 1);
    const productUrl = normalizeKitProductUrl(item.product_url || item.product_code || '');
    const price = Math.max(parseInt(item.price, 10) || 0, 0);
    itemsList += '  - ' + (item.name || '재료') + ' x ' + qty;
    if (price > 0) itemsList += ' / 예상가 ' + price.toLocaleString('ko-KR') + '원';
    if (productUrl) itemsList += ' / ' + productUrl;
    itemsList += '\n';
  }

  const bundleQty = orderContext.bundle_line && orderContext.bundle_line.quantity ? orderContext.bundle_line.quantity : (settlement.student_count || 1);
  const bundlePrice = orderContext.bundle_line && orderContext.bundle_line.settle_price ? Number(orderContext.bundle_line.settle_price) : 0;
  const msg = '📦 <b>재료키트 배송 요청</b>\n\n'
    + '<b>클래스:</b> ' + (cls.class_name || classId) + '\n'
    + '<b>수강생:</b> ' + (settlement.student_name || '-') + '\n'
    + '<b>연락처:</b> ' + (settlement.student_phone || '-') + '\n'
    + '<b>수강일:</b> ' + (settlement.class_date || '-') + '\n'
    + '<b>클래스 수량:</b> ' + (settlement.student_count || 1) + '명\n'
    + '<b>묶음 키트 수량:</b> ' + bundleQty + '개\n'
    + (bundlePrice > 0 ? '<b>묶음 키트 결제액:</b> ' + bundlePrice.toLocaleString('ko-KR') + '원\n\n' : '\n')
    + '<b>키트 구성:</b>\n' + itemsList + '\n'
    + '주문번호: ' + (settlement.order_id || '-');

  try {
    await sendTelegram(msg);
  } catch (e) {
    // 텔레그램 실패해도 정산은 정상 처리
  }
} catch (e) {
  // kit 처리 실패해도 정산은 이미 생성됨 - 로그만
}

return [$input.first()];

// ===================================================
// WF-05 5a-7: 폴링 처리 결과 집계 + 폴링 로그 구성
// 모든 주문 처리 완료 후 집계 데이터 생성
// 참고: SplitInBatches 대신 전체 결과를 Code 노드에서 집계
// ===================================================

const items = $input.all();
const pollMeta = $('Parse Poll Time').first().json;
const filterData = $('Filter Class Orders').first().json;

let created = 0;
let skipped = 0;
let errors = 0;
const settlements = [];

for (const item of items) {
  const d = item.json;
  if (d.Id || d.id) {
    created++;
    // 이전 노드에서 전달된 settlement 데이터 참조
    settlements.push(d);
  } else {
    errors++;
  }
}

// 텔레그램 메시지 구성
let message = '';
if (created > 0 || errors > 0) {
  message = '주문 폴링 완료\n\n'
    + '전체 주문: ' + filterData.totalOrders + '건\n'
    + '클래스 주문: ' + filterData.classOrderCount + '건\n'
    + '정산 생성: ' + created + '건\n';
  if (errors > 0) message += '오류: ' + errors + '건\n';
}

return [{
  json: {
    _logData: {
      poll_time: pollMeta.pollStartTime,
      orders_found: filterData.totalOrders,
      class_orders: filterData.classOrderCount,
      settlements_created: created,
      errors: errors,
      note: ''
    },
    _updatePollTime: true,
    _pollMeta: pollMeta,
    _telegramMessage: message,
    _hasMessage: message.length > 0
  }
}];

// ===================================================
// WF-05 5a-merge: 0건 브랜치와 N건 브랜치의 공통 후처리 합류
// 폴링 로그 기록 + last_poll_time 업데이트
// ===================================================

const data = $input.first().json;
const pollMeta = data._pollMeta;
const logData = data._logData;

// NocoDB tbl_PollLogs 생성용 데이터
const pollLogRecord = {
  poll_time: logData.poll_time,
  orders_found: logData.orders_found,
  class_orders: logData.class_orders || 0,
  settlements_created: logData.settlements_created,
  errors: logData.errors || 0,
  note: logData.note || ''
};

// KST 현재 시각 (last_poll_time 업데이트용)
const now = new Date();
const kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);
const pad = (n) => String(n).padStart(2, '0');
const nowKST = kst.getFullYear() + '-' + pad(kst.getMonth() + 1) + '-' + pad(kst.getDate())
  + ' ' + pad(kst.getHours()) + ':' + pad(kst.getMinutes()) + ':' + pad(kst.getSeconds());

return [{
  json: {
    pollLogRecord,
    nowKST,
    hasRecord: pollMeta.hasRecord,
    recordId: pollMeta.recordId,
    _telegramMessage: data._telegramMessage || '',
    _hasMessage: data._hasMessage || false
  }
}];

// ===================================================
// WF-05 5c: 정합성 검증 -- 파트너별 적립금 집계
// COMPLETED 정산의 reserve_amount를 파트너별로 합산
// 파트너 member_id 매핑 구축
// ===================================================

const settlementsResp = $('Get Completed Settlements').first().json;
const partnersResp = $('Get Active Partners').first().json;

const settlements = settlementsResp.list || [];
const partners = partnersResp.list || [];

// 파트너별 누적 적립금 집계
const partnerTotals = {};
for (const s of settlements) {
  const code = s.partner_code || '';
  if (!code) continue;
  if (!partnerTotals[code]) partnerTotals[code] = 0;
  partnerTotals[code] += Number(s.reserve_amount) || 0;
}

// 파트너 코드 -> member_id 매핑
const partnerMap = {};
for (const p of partners) {
  partnerMap[p.partner_code] = {
    member_id: p.member_id || '',
    partner_name: p.partner_name || ''
  };
}

// 검증 대상 파트너 목록 (적립금이 있는 파트너만)
const checkTargets = [];
for (const code in partnerTotals) {
  if (partnerMap[code] && partnerMap[code].member_id) {
    checkTargets.push({
      partner_code: code,
      member_id: partnerMap[code].member_id,
      partner_name: partnerMap[code].partner_name,
      sheets_total: partnerTotals[code]
    });
  }
}

if (checkTargets.length === 0) {
  return [{
    json: {
      _noTargets: true,
      _discrepancies: [],
      _message: '정합성 검증: 검증 대상 파트너 없음'
    }
  }];
}

// 각 파트너를 개별 아이템으로 출력 (순차 API 호출용)
return checkTargets.map(t => ({ json: { ...t, _noTargets: false } }));

// ===================================================
// WF-05 5c-2: 적립금 조회 결과 비교 + 불일치 감지
// API 조회 성공 여부만 확인 (소비분으로 직접 비교 불가)
// ===================================================

const items = $input.all();
const discrepancies = [];

for (const item of items) {
  const apiResp = item.json;
  // HTTP Request onError: continueRegularOutput이므로 에러도 여기로 옴
  const isError = apiResp.return_code && apiResp.return_code !== '0000';
  const isHttpError = apiResp.statusCode && apiResp.statusCode !== 200;

  // 원래 파트너 데이터는 이전 노드에서 전달
  const partnerData = $('Aggregate Partner Totals').item;

  if (isError || isHttpError) {
    discrepancies.push({
      partner_code: partnerData ? partnerData.json.partner_code : 'unknown',
      member_id: partnerData ? partnerData.json.member_id : 'unknown',
      sheets_total: partnerData ? partnerData.json.sheets_total : 0,
      error: 'API 조회 실패: ' + JSON.stringify(apiResp).substring(0, 200)
    });
  }
}

let message = '';
if (discrepancies.length > 0) {
  message = '정합성 검증 불일치\n\n'
    + discrepancies.length + '건 이상 감지:\n';
  for (const d of discrepancies) {
    message += '- ' + d.partner_code + ': ' + d.error + '\n';
  }
} else {
  message = '정합성 검증 완료: 이상 없음';
}

return [{
  json: {
    discrepancies,
    hasDiscrepancies: discrepancies.length > 0,
    _telegramMessage: message
  }
}];

// ===================================================
// WF-05 5b-1: 카테고리 ID 파싱
// ===================================================

const response = $input.first().json;
const list = response.list || [];

if (list.length === 0 || !list[0].setting_value) {
  return [{
