  }
}];

// ===================================================
// WF-05 5b-2: 메이크샵 상품 vs NocoDB 비교
// 신규/수정/비활성 분류 후 변경 건만 출력
// ===================================================

const productsResp = $('Fetch Makeshop Products').first().json;
const classesResp = $('Get Existing Classes').first().json;

const products = productsResp.list || productsResp.datas || [];
const classes = classesResp.list || [];

// 기존 클래스 맵: makeshop_product_id -> { Id, class_id, class_name, price, status }
const existingMap = {};
for (const c of classes) {
  const pid = String(c.makeshop_product_id || '').trim();
  if (pid) existingMap[pid] = c;
}

// 메이크샵 상품 branduid 집합
const makeshopIds = new Set();
const changes = [];

for (const p of products) {
  const branduid = String(p.branduid || '').trim();
  if (!branduid) continue;
  makeshopIds.add(branduid);

  const existing = existingMap[branduid];
  if (!existing) {
    // 신규 상품
    // 상품명에서 파트너명/클래스명 분리: "[파트너명] 클래스명"
    const name = String(p.name || p.product_name || '').trim();
    let partnerName = '';
    let className = name;
    const bracketEnd = name.indexOf(']');
    if (name.charAt(0) === '[' && bracketEnd > 0) {
      partnerName = name.substring(1, bracketEnd).trim();
      className = name.substring(bracketEnd + 1).trim();
    }

    changes.push({
      action: 'create',
      makeshop_product_id: branduid,
      class_name: className,
      partner_name_hint: partnerName,
      price: Number(p.price || p.sell_price || 0),
      status: 'active'
    });
  } else {
    // 기존 상품: 가격 변경 여부 확인
    const newPrice = Number(p.price || p.sell_price || 0);
    const oldPrice = Number(existing.price || 0);
    if (newPrice !== oldPrice) {
      changes.push({
        action: 'update',
        nocodbId: existing.Id || existing.id,
        makeshop_product_id: branduid,
        class_name: existing.class_name,
        old_price: oldPrice,
        new_price: newPrice
      });
    }
  }
}

// 메이크샵에서 삭제된 상품 -> 비활성 처리
for (const pid in existingMap) {
  if (!makeshopIds.has(pid) && existingMap[pid].status !== 'closed') {
    changes.push({
      action: 'deactivate',
      nocodbId: existingMap[pid].Id || existingMap[pid].id,
      makeshop_product_id: pid,
      class_name: existingMap[pid].class_name
    });
  }
}

// 통계
const stats = {
  total_products: products.length,
  total_classes: classes.length,
  new_count: changes.filter(c => c.action === 'create').length,
  update_count: changes.filter(c => c.action === 'update').length,
  deactivate_count: changes.filter(c => c.action === 'deactivate').length
};

let message = '상품 동기화 완료\n\n'
  + '메이크샵: ' + stats.total_products + '건\n'
  + 'NocoDB: ' + stats.total_classes + '건\n'
  + '신규: ' + stats.new_count + '건\n'
  + '가격수정: ' + stats.update_count + '건\n'
  + '비활성: ' + stats.deactivate_count + '건';

if (changes.length === 0) {
  return [{
    json: {
      _hasChanges: false,
      stats,
      _telegramMessage: message
    }
  }];
}

// 변경 건을 개별 아이템으로 출력
const items = changes.map(c => ({
  json: {
    _hasChanges: true,
    change: c,
    stats,
    _telegramMessage: message
  }
}));

return items;

// ===================================================
// WF-05 5b-3: 변경 건 NocoDB 반영 (Create/Update/Deactivate)
// 각 변경 건에 대해 적절한 HTTP Request 구성
// ===================================================

const items = $input.all();
const baseUrl = 'https://nocodb.pressco21.com/api/v1/db/data/noco/' + $env.NOCODB_PROJECT_ID + '/tbl_Classes';
const results = [];

for (const item of items) {
  const data = item.json;
  if (!data._hasChanges || !data.change) continue;

  const c = data.change;
  results.push({
    json: {
      action: c.action,
      url: c.action === 'create' ? baseUrl : baseUrl + '/' + c.nocodbId,
      method: c.action === 'create' ? 'POST' : 'PATCH',
      body: c.action === 'create'
        ? {
            makeshop_product_id: c.makeshop_product_id,
            class_name: c.class_name,
            price: c.new_price || c.price,
            status: 'active'
          }
        : c.action === 'update'
          ? { price: c.new_price }
          : { status: 'closed' },
      _telegramMessage: data._telegramMessage
    }
  });
}

if (results.length === 0) {
  // 변경 없음
  const firstItem = items[0] ? items[0].json : {};
  return [{
    json: {
      _noChanges: true,
      _telegramMessage: firstItem._telegramMessage || '상품 동기화: 변경 없음'
    }
  }];
}

return results;

// ===================================================
// WF-05 5d-1: FAILED 정산 목록 파싱 + 파트너 member_id 매핑 준비
