  }
}));

return items;

// ===================================================
// WF-05 5d-2: 파트너 member_id 확인 + 적립금 지급 요청 구성
// 적립금 0원이면 자동 COMPLETED
// ===================================================

const partnerResp = $input.first().json;
const partnerList = partnerResp.list || [];
const retryData = $('Parse Failed List').item.json;

// 파트너 없으면 스킵
if (partnerList.length === 0) {
  return [{
    json: {
      _action: 'skip',
      settlement_id: retryData.settlement_id,
      nocodbId: retryData.nocodbId,
      _reason: '파트너 정보 없음'
    }
  }];
}

const memberId = partnerList[0].member_id;
const amount = retryData.reserve_amount;

// 적립금 0원이면 자동 COMPLETED
if (amount <= 0) {
  return [{
    json: {
      _action: 'auto_complete',
      settlement_id: retryData.settlement_id,
      nocodbId: retryData.nocodbId,
      _reason: '적립금 0원'
    }
  }];
}

return [{
  json: {
    _action: 'retry',
    settlement_id: retryData.settlement_id,
    nocodbId: retryData.nocodbId,
    member_id: memberId,
    reserve_amount: amount,
    retry_count: retryData.retry_count,
    order_id: retryData.order_id
  }
}];

// ===================================================
// WF-05 5d-3: 적립금 재시도 결과 판정 + NocoDB 업데이트 구성
// 성공: status=COMPLETED, 실패: retry_count+1
// ===================================================

const apiResp = $input.first().json;
const retryData = $('Prepare Retry').item.json;

let isSuccess = false;
let errorMsg = '';

try {
  if (apiResp.return_code === '0000' && apiResp.datas && apiResp.datas[0]) {
    const result = apiResp.datas[0];
    if (result.result === true || result.result === 1 || result.result === '1') {
      isSuccess = true;
    } else {
      errorMsg = (result.message || []).join(', ') || '알 수 없는 오류';
    }
  } else {
    errorMsg = 'return_code=' + (apiResp.return_code || 'unknown');
  }
} catch (e) {
  errorMsg = e.message || '파싱 오류';
}

const nocodbId = retryData.nocodbId;
const newRetryCount = retryData.retry_count + 1;

if (isSuccess) {
  return [{
    json: {
      _retrySuccess: true,
      nocodbId,
      settlement_id: retryData.settlement_id,
      updateBody: {
        status: 'COMPLETED',
        reserve_paid_date: new Date().toISOString(),
        completed_date: new Date().toISOString(),
        error_message: ''
      }
    }
  }];
} else {
  return [{
    json: {
      _retrySuccess: false,
      nocodbId,
      settlement_id: retryData.settlement_id,
      retry_count: newRetryCount,
      _maxExceeded: newRetryCount >= 5,
      updateBody: {
        status: 'FAILED',
        retry_count: newRetryCount,
        error_message: 'retry:' + newRetryCount + '|' + errorMsg
      }
    }
  }];
}

// ===================================================
// WF-05 5d-4: 재시도 결과 집계 + 텔레그램 메시지
// ===================================================

const items = $input.all();
let successCount = 0;
let failCount = 0;
let maxExceeded = 0;
const details = [];

for (const item of items) {
  const d = item.json;
  if (d._retrySuccess) {
    successCount++;
    details.push('OK: ' + (d.settlement_id || 'unknown'));
  } else if (d._retrySuccess === false) {
    failCount++;
    if (d._maxExceeded) maxExceeded++;
    details.push('FAIL: ' + (d.settlement_id || 'unknown') + ' (retry ' + (d.retry_count || '?') + '/5)');
  }
}

let message = '실패 정산 재시도 결과\n\n'
  + '성공: ' + successCount + '건\n'
  + '실패: ' + failCount + '건\n';
if (maxExceeded > 0) {
  message += '최대 재시도 초과: ' + maxExceeded + '건 (수동 확인 필요)\n';
}
if (details.length > 0) {
  message += '\n' + details.join('\n');
}

return [{
  json: {
    _telegramMessage: message
  }
}];

